// // This module implements a 4-bit register that updates its output 'q' on the falling edge of 'clk' when 'en_n' is high.
module register_4bit(
    input wire [3:0] d,
    input wire clk,
    input wire en_n,
    output reg [3:0] q
);

    always @(posedge clk) begin
        if (!en_n)
            q <= d;
    end

endmodule
